export const getDeleteSuggestionUrl = (id: number, suggestionId: number) => {
  return `/api/projects/${id}/suggestions/${suggestionId}`;
};

export const deleteSuggestion = async (
  id: number,
  suggestionId: number,
  options?: RequestInit,
): Promise<void> => {
  return customFetch<void>(getDeleteSuggestionUrl(id, suggestionId), {
    ...options,
    method: "DELETE",
  });
};

export const getDeleteSuggestionMutationOptions = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof deleteSuggestion>>,
    TError,
    { id: number; suggestionId: number },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof deleteSuggestion>>,
  TError,
  { id: number; suggestionId: number },
  TContext
> => {
  const mutationKey = ["deleteSuggestion"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof deleteSuggestion>>,
    { id: number; suggestionId: number }
  > = (props) => {
    const { id, suggestionId } = props ?? {};

    return deleteSuggestion(id, suggestionId, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type DeleteSuggestionMutationResult = NonNullable<
  Awaited<ReturnType<typeof deleteSuggestion>>
>;

export type DeleteSuggestionMutationError = ErrorType<void>;

/**
 * @summary Delete a suggestion (submitter or owner)
 */
export const useDeleteSuggestion = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof deleteSuggestion>>,
    TError,
    { id: number; suggestionId: number },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof deleteSuggestion>>,
  TError,
  { id: number; suggestionId: number },
  TContext
> => {
  return useMutation(getDeleteSuggestionMutationOptions(options));
};
